def solve(arg1: dict) -> dict:
    users_db = {
        'testuser': 'securepassword'
    }
    roles_db = {
        'testuser': ['admin', 'user']
    }

    username = arg1.get('username')
    password = arg1.get('password')

    if username and password:
        if username in users_db and users_db[username] == password:
            return {'status': 'success', 'token': 'valid_token_string'}
        else:
            return {'status': 'error', 'message': 'Invalid credentials'}

    if username in roles_db:
        return {'roles': roles_db[username]}

    return {'status': 'error', 'message': 'User not found'}

